mapper.insert:
INSERT INTO risk_prompt_version(
    version, content_type, status, prompt_text, model, create_by, publish_by, publish_time, create_time, update_time
) VALUES(
    #{version}, #{contentType}, #{status}, #{promptText}, #{model}, #{createBy}, #{publishBy}, #{publishTime}, NOW(), NOW()
)

mapper.select:
SELECT version, content_type, status, prompt_text, model, create_by, publish_by, publish_time, create_time, update_time
FROM risk_prompt_version
WHERE version = #{version}

SELECT version, content_type, status, prompt_text, model, create_by, publish_by, publish_time, create_time, update_time FROM risk_prompt_version
AND content_type = #{contentType}
ORDER BY create_time DESC, version DESC

mapper.update:
UPDATE risk_prompt_version
SET prompt_text = #{promptText},
    model = #{model},
    update_time = NOW()
WHERE version = #{version}
  AND status = #{expectedStatus}
